sys_script.script:
(function executeRule(current, previous) {

    var check = new GlideRecord('incident');
    check.addQuery('u_medicine', current.getUniqueValue());
    check.addQuery('category', 'Low Stock');
    check.addQuery('state', 'NOT IN', '3,6,7'); // 3=Resolved, 6=Closed, 7=Cancelled
    check.query();
    if (check.next()) return;

    var impact, urgency,priority;
    if (current.quantity == 0) {
        impact = 1;
        urgency = 1;
		priority = 1;
    } else {
        impact = 2;
        urgency = 2;
		priority = 2;

    }

    var inc = new GlideRecord('incident');
    inc.initialize();
    inc.caller_id = gs.getUserID();
    inc.short_description = "Low Stock Alert: " + current.medicine_name;
    inc.description = "Medicine: " + current.medicine_name + "\n" +
                      "Current Quantity: " + current.quantity + "\n" +
                      "Reorder Level: " + current.reorder_level;
    inc.category = "low stock";
    inc.x_1971078_smart_0_u_medicine = current.getUniqueValue();
    inc.impact = impact;
    inc.urgency = urgency;
	inc.priority = priority;
    inc.assignment_group = '1bd92eb14749cb90516b5ac5316d4331';

    inc.insert();

    current.update();

})(current, previous);
